def validate(args, output):
    n = args[0]
    # rebuild a tree from its level-order wire form into [val, left, right] nodes
    def deser(a):
        if not a:
            return None
        root = [a[0], None, None]
        q = [root]; i = 1
        while q and i < len(a):
            node = q.pop(0)
            if i < len(a):
                if a[i] is not None:
                    node[1] = [a[i], None, None]; q.append(node[1])
                i += 1
            if i < len(a):
                if a[i] is not None:
                    node[2] = [a[i], None, None]; q.append(node[2])
                i += 1
        return root
    def is_bst(node, lo, hi):
        if node is None:
            return True
        v = node[0]
        if not (lo < v < hi):
            return False
        return is_bst(node[1], lo, v) and is_bst(node[2], v, hi)
    def inorder(node, acc):
        if node is None:
            return
        inorder(node[1], acc); acc.append(node[0]); inorder(node[2], acc)
    # canonical serialization (preorder with explicit nulls) for distinctness
    def canon(node):
        if node is None:
            return '#'
        return '(' + str(node[0]) + ',' + canon(node[1]) + ',' + canon(node[2]) + ')'
    if n == 0:
        return output == [] or output == [None] or output == [[]]
    target = list(range(1, n + 1))
    seen = set()
    for tw in output:
        root = deser(tw)
        if root is None:
            return False
        if not is_bst(root, float('-inf'), float('inf')):
            return False
        acc = []
        inorder(root, acc)
        if acc != target:
            return False
        key = canon(root)
        if key in seen:
            return False
        seen.add(key)
    catalan = [1] * (n + 1)
    for k in range(1, n + 1):
        c = 0
        for j in range(k):
            c += catalan[j] * catalan[k - 1 - j]
        catalan[k] = c
    return len(seen) == catalan[n]

