function validate(args, output) {
    const n = args[0];
    function deser(a) {
        if (!a || a.length === 0) return null;
        const root = [a[0], null, null];
        const q = [root]; let i = 1;
        while (q.length && i < a.length) {
            const node = q.shift();
            if (i < a.length) { if (a[i] !== null) { node[1] = [a[i], null, null]; q.push(node[1]); } i++; }
            if (i < a.length) { if (a[i] !== null) { node[2] = [a[i], null, null]; q.push(node[2]); } i++; }
        }
        return root;
    }
    function isBst(node, lo, hi) {
        if (node === null) return true;
        const v = node[0];
        if (!(lo < v && v < hi)) return false;
        return isBst(node[1], lo, v) && isBst(node[2], v, hi);
    }
    function inorder(node, acc) {
        if (node === null) return;
        inorder(node[1], acc); acc.push(node[0]); inorder(node[2], acc);
    }
    function canon(node) {
        if (node === null) return '#';
        return '(' + node[0] + ',' + canon(node[1]) + ',' + canon(node[2]) + ')';
    }
    if (n === 0) {
        return (Array.isArray(output) && output.length === 1 && (output[0] === null || (Array.isArray(output[0]) && output[0].length === 0))) || (Array.isArray(output) && output.length === 0);
    }
    const target = [];
    for (let k = 1; k <= n; k++) target.push(k);
    const seen = new Set();
    for (const tw of output) {
        const root = deser(tw);
        if (root === null) return false;
        if (!isBst(root, -Infinity, Infinity)) return false;
        const acc = [];
        inorder(root, acc);
        if (acc.length !== target.length) return false;
        for (let k = 0; k < acc.length; k++) if (acc[k] !== target[k]) return false;
        const key = canon(root);
        if (seen.has(key)) return false;
        seen.add(key);
    }
    const catalan = new Array(n + 1).fill(1);
    for (let k = 1; k <= n; k++) {
        let c = 0;
        for (let j = 0; j < k; j++) c += catalan[j] * catalan[k - 1 - j];
        catalan[k] = c;
    }
    return seen.size === catalan[n];
}

