class Solution:
    def generateTrees(self, n):
        # independent iterative-style construction, then sort by the same
        # canonical key so the emitted order matches the optimal byte for byte
        def build(lo, hi):
            if lo > hi:
                return [None]
            out = []
            for root in range(lo, hi + 1):
                for l in build(lo, root - 1):
                    for r in build(root + 1, hi):
                        node = TreeNode(root)
                        node.left = l
                        node.right = r
                        out.append(node)
            return out
        trees = build(1, n)
        def canon(node):
            if node is None:
                return '#'
            return '(' + str(node.val) + ',' + canon(node.left) + ',' + canon(node.right) + ')'
        trees.sort(key=canon)
        return trees

