var generateTrees = function(n) {
    function build(lo, hi) {
        if (lo > hi) return [null];
        const res = [];
        for (let root = lo; root <= hi; root++) {
            const lefts = build(lo, root - 1);
            const rights = build(root + 1, hi);
            for (const l of lefts) {
                for (const r of rights) {
                    const t = new TreeNode(root);
                    t.left = l;
                    t.right = r;
                    res.push(t);
                }
            }
        }
        return res;
    }
    const trees = build(1, n);
    function canon(node) {
        if (node === null) return '#';
        return '(' + node.val + ',' + canon(node.left) + ',' + canon(node.right) + ')';
    }
    trees.sort((a, b) => {
        const ka = canon(a), kb = canon(b);
        return ka < kb ? -1 : (ka > kb ? 1 : 0);
    });
    return trees;
};
